export interface ProductAnalysis {
  name: string;
  brand: string;
  keyFeatures: string[];
  sellingPoints: string[];
  targetAudience: string;
  painPointsSolved: string[];
  toneRecommendation: string;
}

export interface UGCScene {
  time: string;
  visual: string;
  script: string;
  audioInstruction: string;
}

export interface UGCPrompt {
  hook: string;
  body: string;
  cta: string;
  scenes: UGCScene[];
  visualDirection: string;
}

export enum ImageSize {
  K1 = '1K',
  K2 = '2K',
  K4 = '4K'
}

export enum AspectRatio {
  RATIO_1_1 = '1:1',
  RATIO_2_3 = '2:3',
  RATIO_3_2 = '3:2',
  RATIO_3_4 = '3:4',
  RATIO_4_3 = '4:3',
  RATIO_9_16 = '9:16',
  RATIO_16_9 = '16:9',
  RATIO_21_9 = '21:9'
}

export interface AppState {
  step: 'input' | 'analysis' | 'prompt' | 'image';
  url: string;
  screenshot?: string;
  analysis?: ProductAnalysis;
  ugcPrompt?: UGCPrompt;
  coverImage?: string;
  loading: boolean;
  error?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ProductAnalysis, UGCPrompt, AspectRatio, ImageSize } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const analyzeProduct = async (url: string, screenshotBase64?: string): Promise<ProductAnalysis> => {
  const ai = getAIClient();
  const modelName = 'gemini-3-pro-preview';

  let contents: any;
  const prompt = `Analyze this product from the URL: ${url}. 
    Provide a detailed analysis including its name, brand, key features, selling points, target audience, pain points solved, and a recommended tone for marketing content.`;

  if (screenshotBase64) {
    contents = {
      parts: [
        { text: prompt },
        { inlineData: { mimeType: "image/jpeg", data: screenshotBase64 } }
      ]
    };
  } else {
    contents = prompt;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: contents,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          brand: { type: Type.STRING },
          keyFeatures: { type: Type.ARRAY, items: { type: Type.STRING } },
          sellingPoints: { type: Type.ARRAY, items: { type: Type.STRING } },
          targetAudience: { type: Type.STRING },
          painPointsSolved: { type: Type.ARRAY, items: { type: Type.STRING } },
          toneRecommendation: { type: Type.STRING },
        },
        required: ["name", "brand", "keyFeatures", "sellingPoints", "targetAudience", "painPointsSolved", "toneRecommendation"]
      }
    }
  });

  return JSON.parse(response.text || '{}') as ProductAnalysis;
};

export const generateUGCPrompt = async (analysis: ProductAnalysis): Promise<UGCPrompt> => {
  const ai = getAIClient();
  const modelName = 'gemini-2.5-flash-lite-latest';

  const prompt = `Based on this product analysis: ${JSON.stringify(analysis)}, generate a JSON prompt for a viral UGC (User Generated Content) video. 
    The JSON must include a hook, body, call-to-action (CTA), visual direction, and a scene-by-scene breakdown (visual, script, audio instruction).`;

  const response = await ai.models.generateContent({
    model: modelName,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          hook: { type: Type.STRING },
          body: { type: Type.STRING },
          cta: { type: Type.STRING },
          visualDirection: { type: Type.STRING },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                visual: { type: Type.STRING },
                script: { type: Type.STRING },
                audioInstruction: { type: Type.STRING }
              }
            }
          }
        },
        required: ["hook", "body", "cta", "scenes", "visualDirection"]
      }
    }
  });

  return JSON.parse(response.text || '{}') as UGCPrompt;
};

export const generateCoverImage = async (
  ugcPrompt: UGCPrompt, 
  analysis: ProductAnalysis, 
  aspectRatio: AspectRatio, 
  imageSize: ImageSize
): Promise<string> => {
  const ai = getAIClient();
  const modelName = 'gemini-3-pro-image-preview';

  const visualPrompt = `Professional YouTube/TikTok thumbnail cover for a product called "${analysis.name}". 
    Visual context: ${ugcPrompt.visualDirection}. 
    The style should be high-quality, vibrant, and eye-catching for social media. 
    Main scene: ${ugcPrompt.scenes[0].visual}. No text on the image.`;

  const response = await ai.models.generateContent({
    model: modelName,
    contents: {
      parts: [{ text: visualPrompt }]
    },
    config: {
      imageConfig: {
        aspectRatio: aspectRatio as any,
        imageSize: imageSize as any
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image data found in response");
};

import React, { useState, useCallback, useEffect } from 'react';
import { AppState, ProductAnalysis, UGCPrompt, AspectRatio, ImageSize } from './types';
import { analyzeProduct, generateUGCPrompt, generateCoverImage } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    step: 'input',
    url: '',
    loading: false
  });

  const [hasApiKey, setHasApiKey] = useState<boolean | null>(null);

  useEffect(() => {
    const checkApiKey = async () => {
      // @ts-ignore
      if (window.aistudio && window.aistudio.hasSelectedApiKey) {
        // @ts-ignore
        const result = await window.aistudio.hasSelectedApiKey();
        setHasApiKey(result);
      } else {
        setHasApiKey(true); // Fallback for environments without the helper
      }
    };
    checkApiKey();
  }, []);

  const handleOpenKeySelector = async () => {
    // @ts-ignore
    if (window.aistudio && window.aistudio.openSelectKey) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
      setHasApiKey(true);
    }
  };

  const handleUrlChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setState(prev => ({ ...prev, url: e.target.value }));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setState(prev => ({ ...prev, screenshot: base64String }));
      };
      reader.readAsDataURL(file);
    }
  };

  const startAnalysis = async () => {
    if (!state.url && !state.screenshot) {
      setState(prev => ({ ...prev, error: 'Please provide at least a URL or a screenshot.' }));
      return;
    }

    setState(prev => ({ ...prev, loading: true, error: undefined }));
    try {
      const analysis = await analyzeProduct(state.url, state.screenshot);
      setState(prev => ({ ...prev, analysis, step: 'analysis', loading: false }));
    } catch (err: any) {
      setState(prev => ({ ...prev, error: `Analysis failed: ${err.message}`, loading: false }));
    }
  };

  const createUGCPrompt = async () => {
    if (!state.analysis) return;
    setState(prev => ({ ...prev, loading: true, error: undefined }));
    try {
      const ugcPrompt = await generateUGCPrompt(state.analysis);
      setState(prev => ({ ...prev, ugcPrompt, step: 'prompt', loading: false }));
    } catch (err: any) {
      setState(prev => ({ ...prev, error: `UGC Generation failed: ${err.message}`, loading: false }));
    }
  };

  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.RATIO_9_16);
  const [imageSize, setImageSize] = useState<ImageSize>(ImageSize.K1);

  const createCover = async () => {
    if (!state.ugcPrompt || !state.analysis) return;
    setState(prev => ({ ...prev, loading: true, error: undefined }));
    try {
      const coverImage = await generateCoverImage(state.ugcPrompt, state.analysis, aspectRatio, imageSize);
      setState(prev => ({ ...prev, coverImage, step: 'image', loading: false }));
    } catch (err: any) {
      if (err.message.includes("Requested entity was not found")) {
        setHasApiKey(false);
      }
      setState(prev => ({ ...prev, error: `Image generation failed: ${err.message}`, loading: false }));
    }
