import { GoogleGenAI, Type } from "@google/genai";
import { ProductAnalysis, UGCPrompt, AspectRatio } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const analyzeProduct = async (url: string, screenshotBase64?: string): Promise<ProductAnalysis> => {
  const ai = getAIClient();
  const modelName = 'gemini-3-flash-preview';

  let contents: any;
  const prompt = `Analyze this product from the URL: ${url}. 
    Provide a detailed analysis including its name, brand, key Features, selling points, target audience, pain points solved, and a recommended tone for marketing content.`;

  if (screenshotBase64) {
    contents = {
      parts: [
        { text: prompt },
        { inlineData: { mimeType: "image/jpeg", data: screenshotBase64 } }
      ]
    };
  } else {
    contents = prompt;
  }

  const response = await ai.models.generateContent({
    model: modelName,
    contents: contents,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          brand: { type: Type.STRING },
          keyFeatures: { type: Type.ARRAY, items: { type: Type.STRING } },
          sellingPoints: { type: Type.ARRAY, items: { type: Type.STRING } },
          targetAudience: { type: Type.STRING },
          painPointsSolved: { type: Type.ARRAY, items: { type: Type.STRING } },
          toneRecommendation: { type: Type.STRING },
        },
        required: ["name", "brand", "keyFeatures", "sellingPoints", "targetAudience", "painPointsSolved", "toneRecommendation"]
      }
    }
  });

  return JSON.parse(response.text || '{}') as ProductAnalysis;
};

export const generateUGCPrompt = async (analysis: ProductAnalysis, language: 'en' | 'id'): Promise<UGCPrompt> => {
  const ai = getAIClient();
  const modelName = 'gemini-3-flash-preview';

  const langText = language === 'id' ? 'Indonesian' : 'English';
  const prompt = `Based on this product analysis: ${JSON.stringify(analysis)}, generate a JSON prompt for a viral UGC (User Generated Content) video. 
    IMPORTANT: All text in the script, hook, body, CTA, visual descriptions, and audio instructions MUST BE IN ${langText}.
    The JSON must include a hook, body, call-to-action (CTA), visual direction, and a scene-by-scene breakdown (visual, script, audio instruction).`;

  const response = await ai.models.generateContent({
    model: modelName,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          hook: { type: Type.STRING },
          body: { type: Type.STRING },
          cta: { type: Type.STRING },
          visualDirection: { type: Type.STRING },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                time: { type: Type.STRING },
                visual: { type: Type.STRING },
                script: { type: Type.STRING },
                audioInstruction: { type: Type.STRING }
              }
            }
          }
        },
        required: ["hook", "body", "cta", "scenes", "visualDirection"]
      }
    }
  });

  return JSON.parse(response.text || '{}') as UGCPrompt;
};

export const generateCoverImage = async (
  ugcPrompt: UGCPrompt, 
  analysis: ProductAnalysis, 
  aspectRatio: AspectRatio,
  referenceImage?: string,
  characterImage?: string,
  customInstruction?: string
): Promise<string> => {
  const ai = getAIClient();
  const modelName = 'gemini-2.5-flash-image';

  let visualPrompt = `Professional YouTube/TikTok thumbnail cover for a product called "${analysis.name}". 
    Visual context: ${ugcPrompt.visualDirection}. 
    Main scene: ${ugcPrompt.scenes[0].visual}. 
    The style should be high-quality, vibrant, and eye-catching for social media. No text on the image.`;

  if (customInstruction) {
    visualPrompt += `\nAdditional User Instructions: ${customInstruction}`;
  }

  const parts: any[] = [];

  if (referenceImage) {
    visualPrompt += `\n- Use the attached "Style Reference" image for overall mood, lighting, and composition style.`;
    parts.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: referenceImage
      }
    });
  }

  if (characterImage) {
    visualPrompt += `\n- The person/character in the cover should look exactly like the "Character Reference" image provided.`;
    parts.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: characterImage
      }
    });
  }

  parts.unshift({ text: visualPrompt });

  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts },
    config: {
      imageConfig: {
        aspectRatio: aspectRatio as any
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image data found in response");
};

import React, { useState } from 'react';
import { AppState, AspectRatio } from './types';
import { analyzeProduct, generateUGCPrompt, generateCoverImage } from './services/geminiService';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    step: 'input',
    url: '',
    language: 'id', // Default language set to Indonesian
    loading: false
  });

  const [copied, setCopied] = useState(false);

  const handleUrlChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setState(prev => ({ ...prev, url: e.target.value }));
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setState(prev => ({ ...prev, screenshot: base64String }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleReferenceUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setState(prev => ({ ...prev, referenceImage: base64String }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCharacterUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setState(prev => ({ ...prev, characterImage: base64String }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleInstructionChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setState(prev => ({ ...prev, coverInstruction: e.target.value }));
  };

  const handleLanguageToggle = (lang: 'en' | 'id') => {
    setState(prev => ({ ...prev, language: lang }));
  };

  const startAnalysis = async () => {
    if (!state.url && !state.screenshot) {
      setState(prev => ({ ...prev, error: 'Please provide at least a URL or a screenshot.' }));
      return;
    }

    setState(prev => ({ ...prev, loading: true, error: undefined }));
    try {
      const analysis = await analyzeProduct(state.url, state.screenshot);
      setState(prev => ({ ...prev, analysis, step: 'analysis', loading: false }));
    } catch (err: any) {
      setState(prev => ({ ...prev, error: `Analysis failed: ${err.message}`, loading: false }));
    }
  };

  const createUGCPrompt = async () => {
    if (!state.analysis) return;
    setState(prev => ({ ...prev, loading: true, error: undefined }));
    try {
      const ugcPrompt = await generateUGCPrompt(state.analysis, state.language);
      setState(prev => ({ ...prev, ugcPrompt, step: 'prompt', loading: false }));
    } catch (err: any) {
      setState(prev => ({ ...prev, error: `UGC Generation failed: ${err.message}`, loading: false }));
    }
  };

  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.RATIO_9_16);

  const createCover = async () => {
    if (!state.ugcPrompt || !state.analysis) return;
    setState(prev => ({ ...prev, loading: true, error: undefined }));
    try {
      const coverImage = await generateCoverImage(
        state.ugcPrompt, 
        state.analysis, 
