        <div className="hidden md:flex gap-8 text-sm font-medium text-slate-400">
          <span className={state.step === 'input' ? 'text-white' : ''}>1. Analyze</span>
          <span className={state.step === 'analysis' ? 'text-white' : ''}>2. Insights</span>
          <span className={state.step === 'prompt' ? 'text-white' : ''}>3. Script</span>
          <span className={state.step === 'image' ? 'text-white' : ''}>4. Cover</span>
        </div>
      </nav>

      <main className="max-w-4xl mx-auto px-6 pt-12">
        {state.error && (
          <div className="mb-6 p-4 bg-red-900/30 border border-red-500/50 rounded-xl text-red-200 flex items-center gap-3">
