export default App;

export interface ProductAnalysis {
  name: string;
  brand: string;
  keyFeatures: string[];
  sellingPoints: string[];
  targetAudience: string;
  painPointsSolved: string[];
  toneRecommendation: string;
}

export interface UGCScene {
  voice_over: string;
  tempo: string;
  camera_settings: string;
}

export interface UGCPrompt {
  hook: string;
  body: string;
  cta: string;
  scenes: UGCScene[];
}

export enum ImageSize {
  K1 = '1K',
  K2 = '2K',
  K4 = '4K'
}

export enum AspectRatio {
  RATIO_1_1 = '1:1',
  RATIO_2_3 = '2:3',
  RATIO_3_2 = '3:2',
  RATIO_3_4 = '3:4',
  RATIO_4_3 = '4:3',
  RATIO_9_16 = '9:16',
  RATIO_16_9 = '16:9',
  RATIO_21_9 = '21:9'
}

export type VoiceStyle = 'informative' | 'humor' | 'critical';

export interface AppState {
  step: 'input' | 'analysis' | 'prompt' | 'image';
  url: string;
  analysis?: ProductAnalysis;
  ugcPrompt?: UGCPrompt;
  coverImage?: string;
  referenceImage?: string;
  characterImage?: string;
  coverInstruction?: string;
  language: 'en' | 'id';
  voiceStyle: VoiceStyle;
  loading: boolean;
  error?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ProductAnalysis, UGCPrompt, AspectRatio, VoiceStyle } from "../types";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const analyzeProduct = async (url: string): Promise<ProductAnalysis> => {
  const ai = getAIClient();
  const modelName = 'gemini-3-flash-preview';

  const prompt = `Analyze this product from the URL: ${url}. 
    Provide a detailed analysis including its name, brand, key Features, selling points, target audience, pain points solved, and a recommended tone for marketing content.`;

  const response = await ai.models.generateContent({
    model: modelName,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          brand: { type: Type.STRING },
          keyFeatures: { type: Type.ARRAY, items: { type: Type.STRING } },
          sellingPoints: { type: Type.ARRAY, items: { type: Type.STRING } },
          targetAudience: { type: Type.STRING },
          painPointsSolved: { type: Type.ARRAY, items: { type: Type.STRING } },
          toneRecommendation: { type: Type.STRING },
        },
        required: ["name", "brand", "keyFeatures", "sellingPoints", "targetAudience", "painPointsSolved", "toneRecommendation"]
      }
    }
  });

  return JSON.parse(response.text || '{}') as ProductAnalysis;
};

export const generateUGCPrompt = async (analysis: ProductAnalysis, language: 'en' | 'id', voiceStyle: VoiceStyle): Promise<UGCPrompt> => {
  const ai = getAIClient();
  const modelName = 'gemini-3-flash-preview';

  const langText = language === 'id' ? 'Indonesian' : 'English';
  const prompt = `Based on this product analysis: ${JSON.stringify(analysis)}, generate a JSON prompt for a viral UGC (User Generated Content) video.
    The Voice Over Style must be: ${voiceStyle}.

    IMPORTANT RULES:
    1. All text in the voice_over, hook, body, and cta MUST BE IN ${langText}.
    2. THE OUTPUT JSON MUST ONLY CONTAIN: hook, body, cta, and an array of scenes.
    3. EACH SCENE MUST ONLY CONTAIN: voice_over, tempo (speed instruction), and camera_settings (camera angles/movement).
    4. NO visual descriptions, NO text overlays, NO extra visual instructions.

    Strictly follow this structure.`;

  const response = await ai.models.generateContent({
    model: modelName,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          hook: { type: Type.STRING },
          body: { type: Type.STRING },
          cta: { type: Type.STRING },
          scenes: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                voice_over: { type: Type.STRING },
                tempo: { type: Type.STRING },
                camera_settings: { type: Type.STRING }
              },
              required: ["voice_over", "tempo", "camera_settings"]
            }
          }
        },
        required: ["hook", "body", "cta", "scenes"]
      }
    }
  });

  return JSON.parse(response.text || '{}') as UGCPrompt;
};

export const generateCoverImage = async (
  ugcPrompt: UGCPrompt, 
  analysis: ProductAnalysis, 
  aspectRatio: AspectRatio,
  referenceImage?: string,
  characterImage?: string,
  customInstruction?: string
): Promise<string> => {
  const ai = getAIClient();
  const modelName = 'gemini-2.5-flash-image';

  let visualPrompt = `Professional social media thumbnail cover for a product called "${analysis.name}". 
    The style should be high-quality and eye-catching. 
    Context: A viral UGC video featuring ${analysis.name} with a tone that is ${analysis.toneRecommendation}.
    Primary focus: High impact visual of the product in use or as a hero shot.
    No text on the image.`;

  if (customInstruction) {
    visualPrompt += `\nAdditional User Instructions: ${customInstruction}`;
  }

  const parts: any[] = [];

  if (referenceImage) {
    visualPrompt += `\n- Use the attached "Style Reference" image for overall mood, lighting, and composition style.`;
    parts.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: referenceImage
      }
    });
  }

  if (characterImage) {
    visualPrompt += `\n- The person/character in the cover should look exactly like the "Character Reference" image provided.`;
    parts.push({
      inlineData: {
        mimeType: "image/jpeg",
        data: characterImage
      }
    });
  }

  parts.unshift({ text: visualPrompt });

  const response = await ai.models.generateContent({
    model: modelName,
    contents: { parts },
    config: {
      imageConfig: {
        aspectRatio: aspectRatio as any
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image data found in response");
};

